import React, { useMemo } from 'react';
import { SearchInput } from '@linm-soft-org/linm-web-common-components';
import type { MaterialDto } from '../../services/master/materialApi';
import { createMaterialSearchConfig } from './materialSearchConfig';
import df from '../../styles/documentForm.module.css';

export interface LineMaterialSearchCellProps {
  materialCode: string;
  materialName: string;
  disabled?: boolean;
  onSelect: (material: MaterialDto) => void;
  onClear: () => void;
}

export const LineMaterialSearchCell: React.FC<LineMaterialSearchCellProps> = ({
  materialCode,
  materialName,
  disabled,
  onSelect,
  onClear,
}) => {
  const config = useMemo(() => createMaterialSearchConfig(), []);

  return (
    <td colSpan={2} className={df.tdMaterialSearch}>
      <SearchInput
        config={config}
        value={materialCode}
        primaryDisplay={materialCode}
        secondaryDisplay={materialName}
        onChange={onSelect}
        onClear={onClear}
        showLabel={false}
        className={df.lineMaterialSearch}
        disabled={disabled}
      />
    </td>
  );
};

export const MaterialLineTableHeaders: React.FC = () => (
  <>
    <th className={df.thMatCode}>Mã VT</th>
    <th className={df.thMatName}>Tên VT</th>
  </>
);
